<?php
namespace App\Controllers; use App\Core\Database;
class ReportController { public function index(){ $db=Database::pdo(); if(isset($_GET['export'])){$rows=$db->query('SELECT company_name,company_rut,contact_name,email,industry,city,risk_score,risk_level,risk_status,created_at FROM clients ORDER BY created_at DESC')->fetchAll(); header('Content-Type:text/csv'); header('Content-Disposition:attachment; filename="leads.csv"'); $out=fopen('php://output','w'); fputcsv($out,array_keys($rows[0]??['empresa'=>null])); foreach($rows as $r)fputcsv($out,$r); exit;} \render('reports/index',['byDate'=>$db->query('SELECT DATE(created_at) label,COUNT(*) total FROM clients GROUP BY DATE(created_at) ORDER BY label DESC LIMIT 30')->fetchAll(),'byIndustry'=>$db->query('SELECT industry label,COUNT(*) total FROM clients GROUP BY industry')->fetchAll(),'byRisk'=>$db->query('SELECT risk_level label,COUNT(*) total FROM clients GROUP BY risk_level')->fetchAll(),'avgMonth'=>$db->query('SELECT DATE_FORMAT(created_at,"%Y-%m") label,ROUND(AVG(risk_score),1) total FROM clients GROUP BY label ORDER BY label DESC LIMIT 12')->fetchAll()]);}}
